// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-crea-cita
const input = $input.first().json;

// Extraer datos
const fecha_cita = input.fecha_cita;
const hora_cita = input.hora_cita;
const nombre_cliente = input.nombre_cliente;
const apellido_cliente = input.apellido_cliente;
const modelo_vehiculo = input.modelo_vehiculo;
const patente_vehiculo = input.patente_vehiculo;
const taller_solicitado = input.taller_solicitado;
const servicio_solicitado = input.servicio_solicitado;
const trabajos_extra = input.observaciones_cliente;
const telefono = input.telefono;
// VALIDACIONES
const errores = [];

// 1. VALIDAR FECHA (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!fecha_cita || !regexFecha.test(fecha_cita)) {
  errores.push(`Fecha inválida: "${fecha_cita}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// 2. VALIDAR HORA (HH:MM)
const regexHora = /^\d{2}:\d{2}$/;
if (!hora_cita || !regexHora.test(hora_cita)) {
  errores.push(`Hora inválida: "${hora_cita}". Formato requerido: HH:MM (ej: 10:30)`);
}

// Validar que sea uno de los turnos válidos (08:00 a 10:15 cada 15 min)
const turnosValidos = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15"
];
if (hora_cita && !turnosValidos.includes(hora_cita)) {
  errores.push(`Hora no permitida: "${hora_cita}". Solo se aceptan turnos: ${turnosValidos.join(', ')}`);
}

// 3. VALIDAR NOMBRE CLIENTE (no vacío, mínimo 2 caracteres)
if (!nombre_cliente || nombre_cliente.trim().length < 2) {
  errores.push(`Nombre del cliente inválido: "${nombre_cliente}". Debe tener al menos 2 caracteres`);
}

// 4. VALIDAR APELLIDO CLIENTE (no vacío, mínimo 2 caracteres)
if (!apellido_cliente || apellido_cliente.trim().length < 2) {
  errores.push(`Apellido del cliente inválido: "${apellido_cliente}". Debe tener al menos 2 caracteres`);
}

// 5. VALIDAR MODELO VEHÍCULO (no vacío)
if (!modelo_vehiculo || modelo_vehiculo.trim().length < 2) {
  errores.push(`Modelo del vehículo inválido: "${modelo_vehiculo}". Debe especificarse el modelo`);
}

// 6. VALIDAR PATENTE VEHÍCULO (formato argentino: ABC123 o ABC1234)
// const regexPatente = /^[A-Z]{2,3}\d{3,4}$/i;
// if (!patente_vehiculo || !regexPatente.test(patente_vehiculo.replace(/\s/g, ''))) {
//   errores.push(`Patente inválida: "${patente_vehiculo}". Formato argentino esperado: ABC123 o ABC1234`);
// }

// 5. VALIDAR TELÉFONO (formato argentino)
// Acepta: +549XXXXXXXXXX | 549XXXXXXXXXX | 011XXXXXXXX | 15XXXXXXXX | XXXXXXXXXX (10 dígitos)
const telefonoNormalizado = telefono ? telefono.replace(/[\s\-().]/g, '') : '';
const regexTelefono = /^(\+?549\d{8,10}|0\d{9,10}|15\d{8}|\d{10})$/;
if (!telefono || !regexTelefono.test(telefonoNormalizado)) {
  errores.push(`Teléfono inválido: "${telefono}". Formatos aceptados: +5491123456789, 1123456789, 01123456789`);
}


// 6. VALIDAR TALLER (valores exactos)
const talleresValidos = [
  "Nissan - Tucuman",
  "Nissan - Santiago del Estero"
];
if (!taller_solicitado || !talleresValidos.includes(taller_solicitado)) {
  errores.push(`Taller inválido: "${taller_solicitado}". Valores permitidos: "${talleresValidos[0]}" o "${talleresValidos[1]}"`);
}


// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        fecha_cita,
        hora_cita,
        nombre_cliente,
        apellido_cliente,
        modelo_vehiculo,
        patente_vehiculo,
        taller_solicitado,
        servicio_solicitado,
        trabajos_extra,
        telefono
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados (con patente normalizada)
return [{
  json: {
    success: true,
    fecha_cita,
    hora_cita,
    nombre_cliente: nombre_cliente.trim(),
    apellido_cliente: apellido_cliente.trim(),
    modelo_vehiculo: modelo_vehiculo.trim(),
    patente_vehiculo: patente_vehiculo.replace(/\s/g, '').toUpperCase(),
    taller_solicitado,
    servicio_solicitado,
    trabajos_extra,
    telefono: telefonoNormalizado,
  }
}];

// Procesar respuesta de creación de cita
const response = $input.first().json;

// Verificar si la creación fue exitosa
const exitoso = response.ResponseResult === 0;

  // Buscar el DOC_ID en CustomFields
  const customFields = response.InternalObject?.CustomFields || [];
  const docIdField = customFields.find(field => field.Name === "DOC_ID");
  const docId = docIdField?.Value || docIdField?.ValueOid || null;

if (exitoso) {
  // Cita creada exitosamente
  return {
    json: {
      exitoso: true,
      mensaje: "Cita creada exitosamente",            
      idCita: docId,
      fechaCita: $('trigger-create').first().json.fecha_cita,
      horaCita: $('trigger-create').first().json.hora_cita,
      tallerCita: $('trigger-create').first().json.taller_cita
    }
  };
} else {
  // Hubo un error en la creación
  return {
    json: {
      exitoso: false,
      mensaje: "Error al crear la cita",
      codigoError: response.ResponseResult,
      tipoError: response.ExceptionType || "Desconocido",
      detalleError: response.ExceptionMessage || "Sin detalles",
      informacionAdicional: response.ExceptionInfo || null
    }
  };
}

// Procesar salida con error de validación
const errorData = $input.first().json;

return [{
  json: {
    exitoso: false,
    tipoError: errorData.error || "ERROR_DESCONOCIDO",
    mensaje: "No se pudo crear la cita debido a errores de validación",
    errores: errorData.errores || [],
    cantidadErrores: (errorData.errores || []).length,
    datosRecibidos: {
      fechaCita: errorData.datos_recibidos?.fecha_cita || null,
      horaCita: errorData.datos_recibidos?.hora_cita || null,
      nombreCliente: errorData.datos_recibidos?.nombre_cliente || null,
      apellidoCliente: errorData.datos_recibidos?.apellido_cliente || null,
      modeloVehiculo: errorData.datos_recibidos?.modelo_vehiculo || null,
      patenteVehiculo: errorData.datos_recibidos?.patente_vehiculo || null,
      tallerSolicitado: errorData.datos_recibidos?.taller_solicitado || null,
      servicioSolicitado: errorData.datos_recibidos?.servicio_solicitado || null
    },
    timestamp: new Date().toISOString()
  }
}];

